-- TULIPA · Carga inicial de 92 pessoas (people, não profiles)
-- Pessoas que participam ou participaram do projeto, gerenciadas pela Secretaria.
-- Roda no SQL Editor uma única vez. Pra rerodar, primeiro: delete from public.people;
--
-- 13 pessoas estão sem telefone (marcadas como "Ainda está no projeto?" pelo
-- Gabriel) — entram com phone NULL e uma nota interna pra Secretaria confirmar.


-- Confirma contagem
select count(*) as total_pessoas, count(phone) as com_telefone, count(*) filter (where notes is not null) as a_confirmar
  from public.people;
